import { useParams, useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import products from "../data/ProductData"; // dummy data
import "../index.css";
import { useCart } from "../context/CartContext"; // ✅ correct import

function ProductDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [mainImage, setMainImage] = useState("");
  const [message, setMessage] = useState("");

  const { addToCart } = useCart(); // ✅ use custom hook

  useEffect(() => {
    // 1️⃣ Try dummy data first
    const dummyProduct = products.find((p) => String(p.id) === id);
    if (dummyProduct) {
      setProduct(dummyProduct);
      setMainImage(dummyProduct.image);
      return;
    }

    // 2️⃣ If not found in dummy data → get from DB
    fetch('http://localhost:5000/api/products/${id}')
      .then((res) => res.json())
      .then((data) => {
        setProduct(data);
        setMainImage(data.image);
      })
      .catch((err) => console.error("Error fetching product:", err));
  }, [id]);

  if (!product) {
    return <h2 className="not-found">Product Not Found</h2>;
  }

  const images = [product.image, ...(product.images || [])];

  // ✅ Add to cart
  const handleAddToCart = () => {
    addToCart({
      id: product.id || product._id,
      name: product.name,
      price: product.price,
      image: product.image,
    });
    setMessage("✅ Added to Cart!");
    setTimeout(() => setMessage(""), 2000);
  };

  // ✅ Buy Now → adds to cart + goes to checkout
  const handleBuyNow = () => {
    handleAddToCart();
    navigate("/checkout"); // 🔥 navigate to checkout page
  };

  return (
    <div className="product-details">
      {/* ✅ Floating message */}
      {message && (
        <div
          style={{
            position: "fixed",
            top: "20px",
            right: "20px",
            background: "#28a745",
            color: "#fff",
            padding: "10px 20px",
            borderRadius: "5px",
            boxShadow: "0 2px 6px rgba(0,0,0,0.3)",
            zIndex: 2000,
            animation: "slideDown 0.3s ease",
          }}
        >
          {message}
        </div>
      )}

      {/* Left images */}
      <div className="image-section">
        <div className="main-image">
          <img src={mainImage} alt={product.name} />
        </div>

        <div className="thumbnails">
          {images.map((img, idx) => (
            <div
              key={idx}
              className={'thumb ${mainImage === img ? "active" : ""}'}
              onClick={() => setMainImage(img)}
            >
              <img src={img} alt={'${product.name}-${idx}'} />
            </div>
          ))}
        </div>
      </div>

      {/* Right details */}
      <div className="details-section">
        <h1>{product.name}</h1>
        <p>{product.description}</p>

        <div className="price">
          <span className="offer">₹{product.price}</span>
          {product.oldPrice && <span className="old">₹{product.oldPrice}</span>}
        </div>

        <div className="buttons">
          <button className="btn" onClick={handleAddToCart}>
            Add to Cart
          </button>
          <button className="btn buy" onClick={handleBuyNow}>
            Buy Now
          </button>
        </div>
      </div>

      <style>
        {`
          @keyframes slideDown {
            from { transform: translateY(-20px); opacity: 0; }
            to { transform: translateY(0); opacity: 1; }
          }

          .product-details {
            display: flex;
            flex-wrap: wrap;
            gap: 30px;
            padding: 40px;
            background: #fff;
            border-radius: 10px;
          }

          .image-section img {
            width: 300px;
            border-radius: 10px;
          }

          .details-section {
            flex: 1;
            min-width: 280px;
          }

          .price {
            font-size: 22px;
            margin-top: 10px;
          }

          .price .old {
            text-decoration: line-through;
            color: #999;
            margin-left: 10px;
          }

          .buttons .btn {
            margin-top: 20px;
            margin-right: 15px;
            padding: 10px 18px;
            border: none;
            border-radius: 6px;
            cursor: pointer;
            font-weight: 600;
          }

          .btn.buy {
            background: #007bff;
            color: #fff;
          }

          .btn:hover {
            opacity: 0.9;
          }
        `}
      </style>
    </div>
  );
}

export default ProductDetails;
